mapper.select:
SELECT id, title, content, author_id, author_name, view_count, route_data, route_name, created_at, updated_at FROM qnas
ORDER BY view_count DESC ORDER BY created_at DESC
LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE qnas
SET title = #{title}, content = #{content},
    route_data = #{routeData}, route_name = #{routeName}, updated_at = #{updatedAt}
WHERE id = #{id}
